//
//  LocationManager.swift
//  Radiacode
//
//  Created by Matvey Kozin on 02.10.2023.
//

import Foundation
import CoreLocation
import Combine

final class LocationManager: NSObject, ObservableObject {

    @Published var authorizationStatus: CLAuthorizationStatus = .notDetermined
    @Published var lastKnownLocation: CLLocation?
    @Published var heading: CLHeading?

    private var cancellable: Set<AnyCancellable> = .init()
    private var trackingEnabled: Bool = false
    private var locationContinuations: [CheckedContinuation<Coordinates?, Error>] = []

    private var locationManager: CLLocationManager?

    override init() {
        super.init()
        // Для класса CLLocationManager необходима инициализация на главном потоке, иначе не работает вызов методов делегата!
        Task { @MainActor in
            let locationManager = CLLocationManager()
            // Прогрев первоначального значения authorizationStatus, без него значение определяется некорректно
            locationManager.delegate = self
            locationManager.desiredAccuracy = kCLLocationAccuracyBestForNavigation
            locationManager.allowsBackgroundLocationUpdates = true
            locationManager.showsBackgroundLocationIndicator = true
            locationManager.pausesLocationUpdatesAutomatically = false
            locationManager.distanceFilter = 2

            self.locationManager = locationManager
            self.authorizationStatus = locationManager.authorizationStatus

            if authorizationStatus.isAvailable {
                updateCurrentLocation()
            }
        }

        $authorizationStatus
            .removeDuplicates()
            .receive(on: DispatchQueue.main)
            .sink { status in
                switch status {
                case .notDetermined:
                    self.locationManager?.requestWhenInUseAuthorization()
                case .authorizedWhenInUse:
                    self.locationManager?.requestAlwaysAuthorization()
                    fallthrough
                case .authorizedAlways:
                    if self.lastKnownLocation == nil {
                        self.updateCurrentLocation()
                    }
                default:
                    break
                }
            }
            .store(in: &cancellable)
    }

    func currentLocation() async throws -> Coordinates? {
        try await withCheckedThrowingContinuation { continuation in
            locationContinuations.append(continuation)
            updateCurrentLocation()
        }
    }

    func updateCurrentLocation() {
        if !trackingEnabled {
            locationManager?.startUpdatingLocation()
        }
    }

    func startTracking() {
        trackingEnabled = true
        locationManager?.startUpdatingLocation()
        locationManager?.startMonitoringSignificantLocationChanges()
    }

    func stopTracking() {
        trackingEnabled = false
        locationManager?.stopUpdatingLocation()
        locationManager?.stopMonitoringSignificantLocationChanges()
    }
}

extension LocationManager: CLLocationManagerDelegate {

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        let location = locations.last
        lastKnownLocation = location

        if !locationContinuations.isEmpty {
            let copy = locationContinuations
            locationContinuations.removeAll()
            copy.forEach { $0.resume(returning: location?.coordinates) }
        }

        if !trackingEnabled {
            manager.stopUpdatingLocation()
        }
    }

    func locationManager(_ manager: CLLocationManager, didUpdateHeading newHeading: CLHeading) {
        heading = newHeading
    }

    func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        authorizationStatus = manager.authorizationStatus
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        if !locationContinuations.isEmpty {
            let copy = locationContinuations
            locationContinuations.removeAll()
            copy.forEach { $0.resume(throwing: error) }
        }
    }
}

extension CLAuthorizationStatus {

    var isAvailable: Bool {
        switch self {
        case .authorizedAlways, .authorizedWhenInUse:
            true
        default:
            false
        }
    }
}

private extension CLLocation {
    var coordinates: Coordinates {
        Coordinates(
            latitude: coordinate.latitude,
            longitude: coordinate.longitude
        )
    }
}
